/************************************************************
 * Phase Imbalance Check
 *
 * Tracks the latest value per device (keyed by msg.topic),
 * then calculates the worst % deviation from the average
 * once all expected devices have reported.
 *
 * Parameters are configured via the subflow instance edit panel.
 ************************************************************/
const SAMPLE_COUNT = Number(env.get('SAMPLE_COUNT') ?? 3);
const WARNING_LIMIT_PCT = Number(env.get('WARNING_LIMIT_PCT') ?? 10);
const RED_LIMIT_PCT = Number(env.get('RED_LIMIT_PCT') ?? 25);
// Near-zero average: skip % deviation (division by ~0 is meaningless).
// At very low load all devices read near 0 W, so reporting OK is correct.
const MIN_AVG = 0.0001;
const ROUND_TO = 3;

/******************** helpers ******************************/
function round(n, d) {
    const p = Math.pow(10, d);
    return Math.round(n * p) / p;
}

/******************** main *********************************/
const val = Number(msg.payload);
if (!Number.isFinite(val)) return null;

// Store latest value per device, keyed by msg.topic (node name)
const deviceValues = context.get('deviceValues') || {};
deviceValues[msg.topic] = val;
context.set('deviceValues', deviceValues);

// Wait until we have a reading from each expected device
const readings = Object.values(deviceValues);
const seen = readings.length;
if (seen < SAMPLE_COUNT) {
    node.status({
        fill: 'yellow',
        shape: 'ring',
        text: `waiting (${seen}/${SAMPLE_COUNT})`
    });
    return null;
}

// Calculate average
const avg = readings.reduce((a, b) => a + b, 0) / readings.length;

let worstPct = 0;
const offenders = [];

if (Math.abs(avg) >= MIN_AVG) {
    Object.entries(deviceValues).forEach(([device, v]) => {
        const pct = Math.abs((v - avg) / avg) * 100;
        if (pct > worstPct) worstPct = pct;
        if (pct > WARNING_LIMIT_PCT) offenders.push(device);
    });
}

// Determine severity
let severity, statusText;

if (worstPct <= WARNING_LIMIT_PCT) {
    severity = 0;
    statusText = 'in tolerance';
    node.status({ fill: 'green', shape: 'dot', text: 'in tolerance' });
} else if (worstPct <= RED_LIMIT_PCT) {
    severity = 1;
    statusText = 'imbalance warning';
    node.status({ fill: 'orange', shape: 'ring', text: 'imbalance warning' });
} else {
    severity = 2;
    statusText = 'CRITICAL phase imbalance';
    node.status({ fill: 'red', shape: 'ring', text: 'CRITICAL imbalance' });
}

msg.payload = severity;
msg.text = statusText;
msg.details = {
    deviceValues: Object.fromEntries(
        Object.entries(deviceValues).map(([k, v]) => [k, round(v, ROUND_TO)])
    ),
    avg: round(avg, ROUND_TO),
    worstDeviationPct: round(worstPct, 1),
    offenders
};

return msg;
